import{_ as e,o as a,c as n,f as s}from"./app-55c326ac.js";const i={},l=s(`<h1 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h1><h2 id="安装要求" tabindex="-1"><a class="header-anchor" href="#安装要求" aria-hidden="true">#</a> 安装要求</h2><p><strong>说明：</strong><br> 只需要在一台管理节点或一台主机上安装了Ansible之后，不需要启动或运行一个后台进程，或是添加一个数据库，只要在一台电脑上安装好，就可以通过这台电脑管理一组远程的机器。 在远程被管理的机器上，不需要安装运行任何软件。所以，升级Ansible版本不会有太多问题。</p><h2 id="对托管节点的要求" tabindex="-1"><a class="header-anchor" href="#对托管节点的要求" aria-hidden="true">#</a> 对托管节点的要求</h2><p>通常使用ssh与托管节点通信。默认使用<code>sftp</code>，若<code>sftp</code>不可用，可在<code>ansible.cfg</code>配置文件中配置成<code>scp</code>的方式。在托管的节点上需要安装python2.4以上的版本。低于Python2.5的版本需要额外安装一个模块:<code>python-simplejson</code></p><h2 id="执行安装" tabindex="-1"><a class="header-anchor" href="#执行安装" aria-hidden="true">#</a> 执行安装</h2><p>在Server_01上安装ansible 使用yum安装</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>yum <span class="token parameter variable">-y</span> <span class="token function">install</span> epel-release
yum <span class="token parameter variable">-y</span> <span class="token function">install</span> ansible
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div><p>也可以自己创建RPM软件包。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">git</span> clone  git://github.com/ansible/ansible.git
<span class="token builtin class-name">cd</span> ./ansible
<span class="token function">make</span> <span class="token function">rpm</span>
<span class="token function">rpm</span> <span class="token parameter variable">-Uvh</span> ~/rpmbuild/ansible-*.noarch.rpm

<span class="token comment"># 需要注意的是，在自己创建RPM包的时候，需要安装有 rpm-build make python2-devel</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h2 id="通过pip升级最新的版本" tabindex="-1"><a class="header-anchor" href="#通过pip升级最新的版本" aria-hidden="true">#</a> 通过pip升级最新的版本</h2><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token comment"># 没有pip  </span>
easy-install pip
<span class="token comment"># 安装ansible</span>
pip <span class="token function">install</span> ansible
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,12),d=[l];function c(r,t){return a(),n("div",null,d)}const p=e(i,[["render",c],["__file","安装.html.vue"]]);export{p as default};
